const bearerToken = global.get("bearerToken");
const expiresAt = Number(global.get("expiresIn") || 0);

const valido =
    typeof bearerToken === "string" &&
    bearerToken.trim() !== "" &&
    expiresAt > Date.now();

if (valido) {
    msg.bearerToken = bearerToken.startsWith("Bearer ")
        ? bearerToken
        : `Bearer ${bearerToken}`;
    return [msg, null];
}

msg._originalRequest = {...msg};
return [null, msg];

const authHost = env.get("HOST_DATAWAKE_7413");
const grantType = env.get("PROTHEUS_AUTH_GRANT_TYPE") || "password";
const username =
    env.get("PROTHEUS_AUTH_USERNAME") ||
    env.get("USR_ERP");
const password =
    env.get("PROTHEUS_AUTH_PASSWORD") ||
    env.get("PASS_ERP");

const ausentes = [];
if (!authHost) ausentes.push("HOST_DATAWAKE_7413");
if (!username) ausentes.push("PROTHEUS_AUTH_USERNAME ou USR_ERP");
if (!password) ausentes.push("PROTHEUS_AUTH_PASSWORD ou PASS_ERP");

if (ausentes.length) {
    node.error(`Variáveis ausentes: ${ausentes.join(", ")}`, msg);
    return null;
}

msg.url =
    authHost.replace(/\/$/, "") +
    "/rest/api/oauth2/v1/token";

msg.method = "POST";
msg.headers = {
    grant_type: grantType,
    username,
    password
};

return msg;

let resposta = msg.payload;

if (typeof resposta === "string") {
    try {
        resposta = JSON.parse(resposta);
    } catch (erro) {
        node.error("Resposta de autenticação inválida.", msg);
        return null;
    }
}

const token =
    resposta?.access_token ??
    resposta?.token ??
    resposta?.data?.access_token ??
    resposta?.data?.token;

if (!token) {
    node.error("A autenticação não retornou token.", msg);
    return null;
}

const texto = String(token);
const bearerToken = texto.startsWith("Bearer ")
    ? texto
    : `Bearer ${texto}`;

const segundos = Number(
    resposta?.expires_in ??
    resposta?.expiresIn ??
    resposta?.data?.expires_in ??
    3600
);

const expiresAt =
    Date.now() +
    segundos * 1000 -
    Math.min(300000, Math.max(10000, segundos * 250));

global.set("bearerToken", bearerToken);
global.set("expiresIn", expiresAt);

const original = msg._originalRequest || {};
const restaurada = {...original};
restaurada.bearerToken = bearerToken;
delete restaurada._originalRequest;

return restaurada;

const hostVar = env.get("TARGET_HOST_VAR");
const path = env.get("TARGET_PATH") || "";

if (!hostVar) {
    node.error("TARGET_HOST_VAR não configurada na instância.", msg);
    return null;
}

// Busca a variável da aba pelo nome configurado na instância.
const host = env.get(hostVar);

if (!host) {
    node.error(`Variável de ambiente ${hostVar} não cadastrada.`, msg);
    return null;
}

msg.url = String(host).replace(/\/$/, "") + String(path);
return msg;

node.error(
    `Falha ao gerar token. HTTP ${msg.statusCode || "sem status"}.`,
    msg
);
return null;

const bearerToken = `Bearer ${msg.payload.access_token}`;
const expiresIn = Date.now() + msg.payload.expires_in * 1000 - 5 * 60 * 1000; // pega o tempo de expiração e diminui o tempo em 5 minutos.

//Define variável global para o bearer token e o tempo de expiração
global.set("bearerToken", bearerToken);
global.set("expiresIn", expiresIn);

msg.expiresIn = expiresIn;

return msg;

msg.payload = {
    expiresIn: global.get("expiresIn"),
    bearerToken: global.get("bearerToken")
}

return msg;

/* 
Verificação do tempo de expiração de tokens.
Verifica primeiro se o tempo de expiração do último token está setado (expiresIn).
Se não, isso significa que o token também não foi gerado, e segue o fluxo pra setar um novo (msg.isExpired = true).
Se estiver setado, significa que um token existe, e Verifica se o tempo de expiração desse token foi atingido. Se sim, segue o fluxo pra setar um novo (msg.isExpired = true). Se não, retorna (msg.isExpired = false).
 */

const expiresIn = global.get("expiresIn");
const dataAtual = Date.now();

console.log("\n\n\n\n");
console.log(`expiresIn = ${expiresIn} - ${new Date(expiresIn).toLocaleString('pt-Br')}`);
console.log(`dataAtual = ${dataAtual} - ${new Date(dataAtual).toLocaleString('pt-Br')}`);
console.log(`dataAtual >= expiresIn (token expirou?) ? ${dataAtual >= expiresIn}`);
console.log("\n\n\n\n");

if (expiresIn) {
    msg.isExpired = dataAtual >= expiresIn ? true : false;
} else {
    msg.isExpired = true;
}

return msg;

global.set("bearerToken", undefined);
global.set("expiresIn", undefined);

return msg;

const host = env.get("HOST_DATAWAKE_7413");

if (!host) {
    node.error('Variável de ambiente HOST_DATAWAKE_7413 não cadastrada.', msg);
    return null;
}

let url = host.replace(/\/$/, "") + "/rest/api/oauth2/v1/token";

function readPath(root, path) {
    return path
        .trim()
        .split(".")
        .filter(Boolean)
        .reduce((value, key) => {
            if (value === undefined || value === null) return undefined;
            return value[key];
        }, root);
}

url = url.replace(/\{\{\{?\s*([^}]+?)\s*\}?\}\}/g, (match, expression) => {
    const value = readPath(msg, expression);
    return value === undefined || value === null ? "" : String(value);
});

msg.url = url;
return msg;

