var arrayKits = [];

// as duas classes abaixo são responsáveis pela estrutura do body conforme API:
// POST .../kanban/v1/solicitacao

// armazenará os itens de um kit
class Item {
    constructor(deposito_id, produto_codigo, quantidade) {
        this.deposito_id = deposito_id;
        this.produto_codigo = produto_codigo;
        this.quantidade = quantidade;
    }
}

// classe de um kit/solicitação
class Kit {
    constructor(nr_ordem_producao, unidade_producao_desc, tipo_id, colaborador_codigo, necessidade_data) {
        this.nr_ordem_producao = nr_ordem_producao;
        this.unidade_producao_desc = unidade_producao_desc;
        this.tipo_id = tipo_id;
        this.colaborador_codigo = colaborador_codigo;
        this.necessidade_data = necessidade_data;
        this.kit = [];
    }

    add_to_kit(deposito_id, produto_codigo, quantidade) {
        const myItem = new Item(deposito_id, produto_codigo, quantidade);
        this.kit.push(myItem);
    }
}

