var last_uniprod = "";
var last_op = "";

// loop por cada produto da tabela
msg.payload.forEach(function(element) {
    // se for uma unidade de produção diferente da anterior cria um novo kit
    // assim cada bancada (no caso de abastecimento durante operação) ou linha (no caso de setup) terá seu kit
    // observe que será criada uma nova mensagem/kit para cada unidade de produção diferente
    if (element["uniprod"] != last_uniprod || element["op"] != last_op) {
        last_uniprod = element["uniprod"];
        last_op = element["op"];
        var dueoffset = 86400000; //adicona um dia na data atual para ser a data de necessidade
        var tzoffset = (new Date()).getTimezoneOffset() * 60000; //offset em milliseconds do fuso-horário
        var data_necessidade = (new Date(Date.now() - tzoffset + dueoffset)).toISOString();
        arrayKits.push({ payload: new Kit(element["op"], element["uniprod"], 7, "integracao", data_necessidade) });
    }
    var num_cx = Math.ceil(element["qtd_PI"] / (element["qtd_max_cx"] == 0 ? element["qtd_PI"] : element["qtd_max_cx"]));
    node.warn(element["codigo_PI"] + "-" + num_cx);
    var qtd = 0;
    for (var i = 1; i <= num_cx; i++){
        if (i * element["qtd_max_cx"] < element["qtd_PI"]){
            qtd = element["qtd_max_cx"];
        }
        else{
            qtd = element["qtd_PI"] - ((i-1) * element["qtd_max_cx"]);
        }
        // acrescenta no último kit da array o item
        arrayKits[arrayKits.length - 1].payload.add_to_kit(3, element["codigo_PI"], qtd);
    }
});

// retornando uma array de array de mensagens, assim as mensagens são enviadas em série
// fonte: https://stackoverflow.com/questions/57091563/node-red-sending-multiple-msg-only-returning-first-msg
return [arrayKits];

