function encontrarDocaDestino(produto, destino, mapa) {
    var candidatos = [];

    for (var posicao in mapa) {
        if (mapa[posicao].produtos.includes(produto)) {
            candidatos.push({
                doca: posicao,
                bancadas: mapa[posicao].bancadas
            });
        }
    }


    for (var i = 0; i < candidatos.length; i++) {
        if (candidatos[i].bancadas.includes(destino)) {
            return candidatos[i].doca;
        }
    }


    return candidatos.length > 0 ? candidatos[0].doca : null;
}

